import{_ as a,c as o,o as i,ak as d}from"./chunks/framework.C7_z9xNE.js";const _=JSON.parse('{"title":"问题总结","description":"这里总结了可能遇到的问题以及解决方案。","frontmatter":{"title":"问题总结","description":"这里总结了可能遇到的问题以及解决方案。","layout":"doc"},"headers":[],"relativePath":"version/v3/docs/bug/FAQ.md","filePath":"version/v3/docs/bug/FAQ.md"}'),t={name:"version/v3/docs/bug/FAQ.md"};function r(n,e,c,l,s,p){return i(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="问题总结" tabindex="-1">问题总结 <a class="header-anchor" href="#问题总结" aria-label="Permalink to “问题总结”">​</a></h1><p>这里总结了可能遇到的问题以及解决方案。</p><h2 id="_1-启动时黑屏" tabindex="-1">1. 启动时黑屏 <a class="header-anchor" href="#_1-启动时黑屏" aria-label="Permalink to “1. 启动时黑屏”">​</a></h2><p>启动如果出现黑屏，下面是解决方法</p><p>NVIDIA - 重新安装驱动，并在 NVIDIA App 程序中将 OpenGL GDI 兼容性设为「首选兼容」。 AMD - 尝试安装这个程序驱动：<a href="https://drivers.amd.com/drivers/whql-amd-software-adrenalin-edition-24.10.1-win10-win11-oct-rdna.exe" target="_blank" rel="noreferrer">whql-amd-software-adrenalin-edition-24.10.1-win10-win11-oct-rdna</a>。</p><div class="tip custom-block"><p class="custom-block-title">小提示</p><p>点击蓝字即可跳转至网站</p></div><h2 id="_2-不跟随导航" tabindex="-1">2.不跟随导航 <a class="header-anchor" href="#_2-不跟随导航" aria-label="Permalink to “2.不跟随导航”">​</a></h2><p>此问题很可能是由于您的软件设置中未启用 ETS2LA 遵循导航路线所致。如果您的车道辅助叠加窗口与左侧所示相似，请按 N 键启用导航。此时，叠加窗口将显示 <code>Active - Navigating</code>，表明导航已启用。</p><h2 id="_3-转向速度过慢" tabindex="-1">3. 转向速度过慢 <a class="header-anchor" href="#_3-转向速度过慢" aria-label="Permalink to “3. 转向速度过慢”">​</a></h2><p>只要 ETS2LA 正在向游戏发送转向输出，那么问题就出在游戏这边。最可能的原因是灵敏度设置不正确，导致游戏无法以线性方式响应我们的输出。（可以通过查看日志来判断）</p><p>重置控制设置的最简单方法是，在游戏的控制设置中再次运行快速设置。如果你想尝试手动解决此问题，请设置以下选项：</p><ul><li>Sensitivity —— <code>0.5</code> or <code>1.0</code>. This depends on variables we&#39;ve yet to figure out.</li><li>Steering Non-Linearity —— <code>0</code></li><li>Speed Sensitive Steering —— <code>Disabled</code></li></ul><h2 id="_4-在mod地图中无法使用" tabindex="-1">4.在mod地图中无法使用 <a class="header-anchor" href="#_4-在mod地图中无法使用" aria-label="Permalink to “4.在mod地图中无法使用”">​</a></h2><p>虽然我们支持大多数模组，但无法保证100%兼容。您可以采取以下措施，尝试提升游戏体验。（加密mod中尤为常见）</p><ul><li>如果遇到崩溃 ——在 <code>Settings - Data</code> 降低数据质量。</li><li>如果车道辅助显示 <code>No nearby nodes</code> 且内部可视化为空 ——请尝试在 <code>Settings - Data</code> 启用 <code>Force Base Map Name</code>。如果不行，确保 mod 文件夹只包含你正在使用的 mod。ETS2LA 会加载该文件夹中发现的所有模组，无论游戏内是否启用。</li></ul><h2 id="_5-我在在游戏里-但日志显示加载游戏数据失败" tabindex="-1">5. 我在在游戏里，但日志显示加载游戏数据失败 <a class="header-anchor" href="#_5-我在在游戏里-但日志显示加载游戏数据失败" aria-label="Permalink to “5. 我在在游戏里，但日志显示加载游戏数据失败”">​</a></h2><p>当你的 <code>game.log.txt</code> 不在 ETS2LA 预期的位置时会遇到此类问题，这是很常见的问题。我们已经设计了一个后备方案来绕过这些情况。你可以在 <code>Settings - Data</code> 中启用 <code>Force Map Load</code> ，强制 ETS2LA 加载第一个匹配游戏。</p>',17)])])}const m=a(t,[["render",r]]);export{_ as __pageData,m as default};
